import React, { useState, useEffect } from 'react';
import axios from 'axios';
import '../styles/styles.css';  // Assuming you have an external CSS file for styling

const TransactionPage = () => {
    const [transactions, setTransactions] = useState([]);  // Store transaction data
    const [isLoading, setIsLoading] = useState(true);  // Loading state
    const [error, setError] = useState(null);  // Error state
    const [transactionData, setTransactionData] = useState({
        senderUser: '',
        receiverUser: '',
        amount: '',
    });  // State for form data
    const [isSubmitting, setIsSubmitting] = useState(false);  // State for submit button

    const queryParams = new URLSearchParams(location.search);
    const user = queryParams.get('user'); // Get user from URL query params

    useEffect(() => {
        // Fetch the transaction data from the server when the component mounts
        const fetchTransactions = async () => {
            try {
                const response = await axios.get('http://localhost:3003/transactions');
                setTransactions(response.data.transactions);  // Assuming response.data is an array of transactions
                console.log("response data: " + response.data.transactions);
            } catch (err) {
                setError('Failed to fetch transactions');
            } finally {
                setIsLoading(false);  // Set loading to false once data is fetched or error occurred
            }
        };

        fetchTransactions();
    }, []);  // Empty dependency array, fetch data only once when the component mounts

    // If the component is still loading, show a loading message
    if (isLoading) {
        return <div className="loading">Loading transactions...</div>;
    }

    // If there's an error fetching data, display an error message
    if (error) {
        return <div className="error">{error}</div>;
    }

    // Handle the transaction submission
    const handleSubmitTransaction = async (e) => {
        e.preventDefault();
        setIsSubmitting(true);  // Disable the button while submitting

        try {
            // Send a POST request to the server with transaction data
            const response = await axios.post('http://localhost:3003/transactions', {
                // senderUser: user, //transactionData.senderUser,
                receiverUsername: transactionData.receiverUser,
                amount: transactionData.amount,
            });

            if (response.data.success) {
                // Successfully submitted the transaction, update the transaction list
                // setTransactions([...transactions, response.data.transaction]);
                setTransactions((prevTransactions) => [
                    ...prevTransactions,
                    response.data.transaction
                ]);


                // Optionally, reset form data
                setTransactionData({
                    // senderUser: '',
                    receiverUser: '',
                    amount: '',
                });

                console.log("HEREERERER" + response.data);

                await fetchTransactions();
            } else {
                setError('Failed to send transaction');
            }
        } catch (err) {
            setError('Failed to send transaction');
        } finally {
            setIsSubmitting(false);  // Re-enable the button
        }
    };

    // Handle form input changes
    const handleInputChange = (e) => {
        const { name, value } = e.target;
        setTransactionData((prevState) => ({
            ...prevState,
            [name]: value,
        }));
    };

    return (
        <div className="transaction-page">
            <h1>Transaction Page For</h1>
            <h1>{user}</h1>

            {/* Transaction Form */}
            <form onSubmit={handleSubmitTransaction} className="transaction-form">
                {/*<label>*/}
                {/*    Sender:*/}
                {/*    <input*/}
                {/*        type="text"*/}
                {/*        name="senderUser"*/}
                {/*        value={transactionData.senderUser}*/}
                {/*        onChange={handleInputChange}*/}
                {/*        required*/}
                {/*    />*/}
                {/*</label>*/}
                <label>
                    Receiver:
                    <input
                        type="text"
                        name="receiverUser"
                        value={transactionData.receiverUser}
                        onChange={handleInputChange}
                        required
                    />
                </label>
                <label>
                    Amount:
                    <input
                        type="number"
                        name="amount"
                        value={transactionData.amount}
                        onChange={handleInputChange}
                        required
                    />
                </label>
                <button type="submit" disabled={isSubmitting}>Send Transaction</button>
            </form>

            <table className="transaction-table">
                <thead>
                <tr>
                    <th>Date</th>
                    <th>Transaction ID</th>
                    <th>Amount</th>
                    <th>Sender</th>
                    <th>Receiver</th>
                </tr>
                </thead>
                <tbody>
                {transactions.map((transaction) => (
                    <tr key={transaction.id}>
                        <td>{transaction.date}</td>
                        <td>{transaction._id}</td>
                        <td>{transaction.amount}</td>
                        <td>{transaction.senderUser}</td>
                        <td>{transaction.receiverUser}</td>
                    </tr>
                ))}
                </tbody>
            </table>
        </div>
    );
};

export default TransactionPage;
